import { useTranslation } from 'react-i18next'
import { IconButton, InlineButton, Row } from '@fs/zion-ui'
import { ContentReply } from '@fs/zion-icon'
import React from 'react'
import { useHistory } from '@fs/zion-router'
import { CHAT_MESSAGE_TYPE } from '../helpers/stream/streamChatHelper'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../chat-memory-router/ChatMemoryRouter'

export default function ChatMessageReplyButtons({ message, channel }) {
  const [t] = useTranslation()
  const history = useHistory()
  const replies = (message?.reply_count ?? 0) - (message?.deleted_reply_count ?? 0)
  const onClick = () => {
    history.push(buildChatRoute(CHAT_ROUTE_KEY.CHAT, { cid: channel.cid, pid: message.id }))
  }

  const replyText = t(
    'chat.message-replies.action-plural',
    '{count, plural, =0 {No Replies} one {# Reply} other {# Replies}}',
    { count: replies }
  )

  return (
    <Row gutters="nano" alignY="middle" data-testid="chat-message-reply-buttons">
      {replies > 0 && <InlineButton onClick={onClick}>{replyText}</InlineButton>}
      {message?.type !== CHAT_MESSAGE_TYPE.DELETED && (
        <IconButton onClick={onClick} size="xs" Icon={ContentReply} title={t('chat.message-reply.action', 'Reply')} />
      )}
    </Row>
  )
}
